### Swift Protocol Extensions

Protocol extensions allow you to provide default implementations for protocol methods and computed properties. This is a core feature of protocol-oriented programming in Swift.

**Providing Default Implementations:**

```swift
protocol Greetable {
    var name: String { get }
    func greet() -> String
}

// Default implementation via protocol extension
extension Greetable {
    func greet() -> String {
        return "Hello, \(name)!"
    }
}

// Conforming types get the default for free
struct Person: Greetable {
    let name: String
}

struct Robot: Greetable {
    let name: String
    func greet() -> String {
        return "Beep boop, I am \(name)"
    }
}

print(Person(name: "Alice").greet())  // Hello, Alice!
print(Robot(name: "R2D2").greet())   // Beep boop, I am R2D2
```

**Adding Computed Properties:**

```swift
protocol NumericValue {
    var value: Double { get }
}

extension NumericValue {
    var squared: Double { value * value }
    var half: Double { value / 2 }
    func isGreaterThan(_ other: Double) -> Bool { value > other }
}

struct Temperature: NumericValue {
    var value: Double
}

let temp = Temperature(value: 25)
print(temp.squared)  // 625.0
```

**Constrained Protocol Extensions:**

```swift
// Extension only applies when Element is Equatable
extension Collection where Element: Equatable {
    func containsDuplicates() -> Bool {
        let unique = Set(self)
        return unique.count != count
    }
}

let numbers = [1, 2, 3, 4, 5]
print(numbers.containsDuplicates())  // false

let withDupes = [1, 2, 3, 2, 1]
print(withDupes.containsDuplicates())  // true
```

**Protocol Extension Benefits:**

| Benefit | Description |
|---------|-------------|
| Code reuse | Define behavior once, use everywhere |
| Optional methods | Default implementations make methods optional |
| Type constraints | Apply extensions only to specific conforming types |
| Mixin behavior | Compose functionality without inheritance |

```swift
protocol Identifiable {
    var id: String { get }
}

extension Identifiable {
    func identify() -> String {
        return "My ID is \(id)"
    }
}

extension Identifiable where Self: Equatable {
    func isSame(as other: Self) -> Bool {
        return id == other.id
    }
}
```

> **Key Point:** Protocol extensions with default implementations enable protocol-oriented programming. Types get behavior automatically, but can still provide their own custom implementations if needed.

Protocol extensions can also add constraints using `where` clauses to limit the extension to specific conforming types.

codeExample:
import Foundation

protocol Vehicle {
    var make: String { get }
    var year: Int { get }
    func start() -> String
}

// Default implementations
extension Vehicle {
    func start() -> String {
        "\(make) (\(year)) engine started"
    }

    var age: Int {
        let currentYear = 2024
        return currentYear - year
    }

    func description() -> String {
        "\(year) \(make) - \(age) years old"
    }
}

// Constrained extension
protocol Racing { }

extension Vehicle where Self: Racing {
    func start() -> String {
        "\(make) (\(year)) - RACING MODE ACTIVATED!"
    }
}

struct Car: Vehicle, Racing {
    let make: String
    let year: Int
}

struct Truck: Vehicle {
    let make: String
    let year: Int
}

let car = Car(make: "Ferrari", year: 2023)
let truck = Truck(make: "Ford", year: 2020)

print(car.description())
print(car.start())  // Racing mode (Racing protocol)
print(truck.start())  // Default implementation
